module LU_Decomposition (
    input [7:0] a11, a12,
    input [7:0] a21, a22,
    output [7:0] l11, l12, l21, l22,
    output [7:0] u11, u12, u21, u22
);
  assign u22 = a22 - l21 * u12;
  assign u21 = 8'h0;
  assign u12 = a12;
  assign u11 = a11;

  assign l22 = 8'h1;
  assign l21 = a21 / a11;
  assign l12 = 8'h0;
  assign l11 = 8'h1;
endmodule
